var e=JSON.parse(`[{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"사, 살려주세요! 전대장님!","JPN":"た、助けてください！　戦隊長！","ENG":"S-save us! Commander!","TWN":"救，救救我們！戰隊長！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"조용히 살겠습니다! 아무것도 안 하고 그냥 바라만 보겠습니다!","JPN":"大人しくしますから！　何もせずに、ただ見てますから！","ENG":"We'll live quietly! We won't do anything and just observe!","TWN":"我們會很安分的！什麼都不做，只是靜靜地看著！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_41"},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"우린 그냥 다시 함께하고 싶을 뿐이야! 우린 그냥 예전처럼 같이 있고 싶었다고!","JPN":"私たちはただ、もう一度共にしたかっただけだ！　昔のように一緒にいたいだけなんだ！","ENG":"All we wanted was to be with you again! We just wanted to be together like old times!","TWN":"我們只是想再次和戰隊長在一起！和以前一樣！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_MINI_MOVE_START"},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"이렇게…… 정말 이렇게 동료들을 등지는 겁니까?","JPN":"本当に……本当にこうやって仲間から目を背けるんですか？","ENG":"Are you... really going to turn your back on your comrades?","TWN":"你真的……要乓拋棄你的同伴嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_40"},{"id":"L20_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"동료들은 돌아오지 않아. 이 사실을 되돌릴 순 없어.","JPN":"仲間たちはもう生き返りはしない。この事実を元に戻すことはできない。","ENG":"My comrades are never coming back. I cannot change this fact.","TWN":"戰友們已經不會再回來，這是個既定的事實。"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_SURYA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_10"},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 나는 그럼에도…… 일어서야 해.","JPN":"しかし私はそれでも……立ち上がらなければならない。","ENG":"But regardless... I must get back on my feet.","TWN":"但即便如此……我依然必須站起來。"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_SURYA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_11"},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"모든 걸 잃었을지라도, 앞으로 나아가야 하니까!","JPN":"すべてを失ったとしても、前に進まなければならないのだ！","ENG":"For even if I have lost everything, I must go forth!","TWN":"因為就算失去所有，仍然要繼續前進！"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_SURYA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_12"},{"id":"L33_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_COMMANDER","text":{"KOREA":"안돼!!!!! 죽고 싶지 않아! 사라지고 싶지 않아!!!!","JPN":"ダメだ！！！！！　死にたくない！　消えたくない！！！！","ENG":"NO!!!! I don't want to die! I DON'T WANT TO DISAPPEAR!!!","TWN":"不！！！我不想死！我不想消失！！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L38_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>살……</color>려…….","JPN":"<color=#ff3636>助け……</color>て……","ENG":"<color=#ff3636>Save...</color> us...","TWN":"<color=#ff3636>救……</color>救我們……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L42_1","type":"dialog","speaker":"OPR_VARUNA_NPC_ADMIN","text":{"KOREA":"적성 개체 반응 소멸…….","JPN":"敵性個体の反応消滅……","ENG":"The hostile response has disappeared...","TWN":"敵人反應消失……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_VARUNA_NPC_ADMIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":"OPR_VARUNA_NPC_ADMIN","text":{"KOREA":"침식파 밀도…… 하강하고 있습니다.","JPN":"侵食波密度……下がっています。","ENG":"Corruption ray density... is also decreasing.","TWN":"侵蝕波密度……正在下降。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_VARUNA_NPC_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"OPR_VARUNA_NPC_ADMIN","text":{"KOREA":"침식체 토벌 완료! 전파합니다! 침식체 토벌 완료!","JPN":"侵食体の討伐完了！　お伝えします！　侵食体の討伐完了！","ENG":"C.O. extermination complete! Spread the word! The C.O. has been exterminated!","TWN":"侵蝕體討伐完成！轉述！侵蝕體討伐完成！"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_VARUNA_NPC_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"끝, 끝났다아…….","JPN":"お、終わったあ……","ENG":"I-it's finally over...","TWN":"結，結束了……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"쉽지 않은 상대였어요. 여러 가지로.","JPN":"手ごわい相手でした。いろんな意味で。","ENG":"It wasn't an easy opponent. I mean that in a lot of ways.","TWN":"是個不容易對付的對手呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"고생하셨습니다. 전대장님.","JPN":"お疲れ様でした。戦隊長。","ENG":"Great work, Commander.","TWN":"辛苦了，戰隊長。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"……그래.","JPN":"……ああ。","ENG":"...Yes.","TWN":"……是。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"너희는 편히 잠들었을까?","JPN":"君たちは安らかに眠っているのだろうか。","ENG":"Have you all found peace?","TWN":"你們有進入安息嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"내가 내린 결정이, 과연 옳은 선택이었을까?","JPN":"私の決断が、果たして正しい選択だったのだろうか。","ENG":"Was the decision I made the right one?","TWN":"我所做的決定，究竟是不是正確的選擇？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"아직도 난 잘 모르겠어.","JPN":"未だによくわからない。","ENG":"I still don't know.","TWN":"我到現在還是無法肯定。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"대답을 듣고 싶지만, 난 아직 앞으로 나아가야 해.","JPN":"答えを聞きたいが、私はまだ前に進まなければならない。","ENG":"I wish to hear an answer, but I still must move on.","TWN":"雖然我想聽到答案，但我還得繼續前進。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"언젠간 너희의 곁으로 돌아갈 때가 오겠지.","JPN":"いつか君たちの元へ帰る時が来るだろう。","ENG":"A day will come when I return to your side.","TWN":"總有一天我會回到你們身邊的。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"그때가 돼서 너희를 만난다면, 대답해줘.","JPN":"その時が来て君たちに会ったら、答えてくれ。","ENG":"When that day comes, please give me an answer.","TWN":"到時候如果遇見你們，請回答我。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"내가 내린 선택이 과연 옳은 것이었는지.","JPN":"私の選択が正しいものだったのか。","ENG":"If my decision was right or not.","TWN":"我的選擇是正確的嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"침식체 정화를 완료했으니 이만 귀환한다.","JPN":"侵食体の浄化は完了した。これより帰還する。","ENG":"The C.O. has been purified. We will now return home.","TWN":"……侵蝕體淨化完畢，準備歸隊。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"모두들 고생 많았다.","JPN":"皆、ご苦労だった。","ENG":"Good work, everyone.","TWN":"大家都辛苦了。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};